__kernel void hotspotOpt1(__global const float* pIn,
                          __global const float* tIn,
                          __global float* tOut,
                          float stepDivCap,
                          int numCols,
                          int numRows,
                          int layers,
                          float ce,
                          float cw,
                          float cn,
                          float cs,
                          float ct,
                          float cb,
                          float cc)
{
    int x = get_global_id(0);
    int y = get_global_id(1);

    if (x >= numCols || y >= numRows)
        return;

    float amb_temp = 80.0f;

    for (int z = 0; z < layers; z++)
    {
        int c = x + y * numCols + z * numCols * numRows;

        int w = (x == 0) ? c : c - 1;
        int e = (x == numCols - 1) ? c : c + 1;
        int n = (y == 0) ? c : c - numCols;
        int s = (y == numRows - 1) ? c : c + numCols;
        int b = (z == 0) ? c : c - numCols * numRows;
        int t = (z == layers - 1) ? c : c + numCols * numRows;

        tOut[c] = cc * tIn[c] + cw * tIn[w] + ce * tIn[e]
                  + cs * tIn[s] + cn * tIn[n] + cb * tIn[b] + ct * tIn[t]
                  + stepDivCap * pIn[c] + ct * amb_temp;
    }
}
